import React, { useState, useRef } from "react";
import { Container, Button, Form, Card, Alert } from "react-bootstrap";
import "bootstrap/dist/css/bootstrap.min.css";
import "./home2.css";

function SpellingGame() {
  const words = ["apple", "banana", "cane", "strawberry", "cage"];
  const [currentWord, setCurrentWord] = useState(words[0]);
  const [userInput, setUserInput] = useState("");
  const [message, setMessage] = useState("");
  const [incorrectAttempts, setIncorrectAttempts] = useState(0);
  const [hintIndex, setHintIndex] = useState(0);
  const [hintRevealed, setHintRevealed] = useState([]);
  const [showRevealButton, setShowRevealButton] = useState(false);
  
  const hintPattern = [0, currentWord.length - 1, 1, currentWord.length - 2];
  const inputRef = useRef(null);

  const getHint = () => {
    if (hintIndex < hintPattern.length) {
      setHintRevealed([...hintRevealed, hintPattern[hintIndex]]);
      setHintIndex(hintIndex + 1);
    } else {
      setShowRevealButton(true);
    }
  };

  const revealWord = () => {
    setHintRevealed([...Array(currentWord.length).keys()]);
  };

  const checkSpelling = () => {
    if (userInput.toLowerCase() === currentWord.toLowerCase()) {
      setMessage("✅ Correct! Well done!");
      setUserInput("");
    } else {
      setIncorrectAttempts(incorrectAttempts + 1);
      setMessage("❌ Incorrect! Try again.");
    }
  };

  return (
    <Container className="text-center mt-5">
      <Card className="p-4">
        <h1>Spelling Game</h1>
        <h2>Spell the word:</h2>

        <div className="hint-box">
          {currentWord.split('').map((letter, index) => (
            <span key={index} className="hint-letter">
              {hintRevealed.includes(index) ? letter : "_"}
            </span>
          ))}
        </div>

        <Form.Control
          type="text"
          value={userInput}
          onChange={(e) => setUserInput(e.target.value)}
          className="mb-3"
          ref={inputRef}
        />
        <Button variant="success" onClick={checkSpelling}>Submit</Button>
        <p className="mt-3">{message}</p>
        <p>Incorrect Attempts: {incorrectAttempts} / 6</p>

        <div className="hint-container mt-3">
          {!showRevealButton ? (
            <Button variant="warning" onClick={getHint}>Get Hint</Button>
          ) : (
            <Button variant="danger" onClick={revealWord}>Reveal Word</Button>
          )}
        </div>
      </Card>
    </Container>
  );
}

export default SpellingGame;
